// Paginate limits the query to a specific page and calculates the total count.
func (q *DisposableTableQuery) PaginateWithCount(
	ctx context.Context, page int, pageSize int,
) (*DisposableTableCountPagination, error) {
	if page < 1 {
		page = 1
	}
	if pageSize < 1 {
		pageSize = 10
	}
	offset := (page - 1) * pageSize

	_, colMappers, err := q.buildSelect()
	if err != nil {
		return nil, err
	}

	clone := q.Limit(pageSize).Offset(offset)
	queryStr, args, err := clone.ToSelectSQL(1, true)
	if err != nil {
		return nil, err
	}

	rows, err := clone.db.QueryContext(ctx, queryStr, args...)
	if err != nil {
		return nil, err
	}
	defer func(rows *sql.Rows) {
		_ = rows.Close()
	}(rows)

	var results []*DisposableTable
	var totalCount int

	ptrs := make([]any, len(colMappers)+1)
	ptrs[len(colMappers)] = &totalCount

	for rows.Next() {
		var row DisposableTable
		for i, mapper := range colMappers {
			mapper(&row, ptrs, i)
		}

		err = rows.Scan(ptrs...)
		if err != nil {
			return nil, err
		}
		results = append(results, &row)
	}

	err = rows.Err()
	if err != nil {
		return nil, err
	}

	if len(results) > 0 {
		err := clone.loadEdges(ctx, results)
		if err != nil {
			return nil, err
		}
	}

	return &DisposableTableCountPagination{
		Items:      results,
		TotalCount: totalCount,
	}, nil
}

// PaginateSimple executes the query and returns a paginated result set without a total count.
// Instead, it fetches one extra record to determine if there are more records available.
func (q *DisposableTableQuery) PaginateSimple(
	ctx context.Context, page int, pageSize int,
) (*DisposableTableSimplePagination, error) {
	if page < 1 {
		page = 1
	}
	if pageSize < 1 {
		pageSize = 10
	}

	limit := pageSize + 1
	offset := (page - 1) * pageSize

	items, err := q.Limit(limit).Offset(offset).Get(ctx)
	if err != nil {
		return nil, err
	}

	hasMore := false
	if len(items) > pageSize {
		hasMore = true
		items = items[:pageSize]
	}

	return &DisposableTableSimplePagination{
		Items:   items,
		HasMore: hasMore,
	}, nil
}

