// Update applies the provided options to all Post records matching
// the current query constraints. It returns the updated records if a RETURNING
// clause is used, or the number of affected rows otherwise.
func (q *PostQuery) Update(
	ctx context.Context, opts ...PostUpdateOption,
) (*Post, error) {
	res, _, err := q.UpdateMany(ctx, opts...)
	if err != nil {
		return nil, err
	}
	if len(res) == 0 {
		return nil, nil
	}
	return res[0], nil
}

func (q *PostQuery) UpdateMany(
	ctx context.Context, opts ...PostUpdateOption,
) ([]*Post, int64, error) {
	if len(opts) == 0 {
		return nil, 0, errors.New("no update options provided")
	}

	m := make(map[rootpkg.Column]any)
	for _, opt := range opts {
		opt(m)
	}

	if len(m) == 0 {
		return nil, 0, errors.New("no columns to update")
	}

	var query strings.Builder
	var numBuf [20]byte
	query.Grow(256)
	query.WriteString(`UPDATE "public"."posts"`)
	if q.alias != "" {
		query.WriteString(" AS ")
		query.WriteString(q.alias)
	}
	query.WriteString(" SET ")

	var args = make([]any, 0, len(m)+16)
	paramIdx := 1

	i := 0
	for col, val := range m {
		if i > 0 {
			query.WriteString(", ")
		}
		query.WriteString(col.String())
		if val == nil {
			query.WriteString(" = NULL")
		} else {
			query.WriteString(" = $")
			query.Write(strconv.AppendInt(numBuf[:0], int64(paramIdx), 10))
			args = append(args, val)
			paramIdx++
		}
		i++
	}

	if len(q.wheres) > 0 {
		query.WriteString(" WHERE ")
		whereSQL, whereArgs, err := rootpkg.BuildConditions(q.wheres, &paramIdx)
		if err != nil {
			return nil, 0, err
		}
		query.WriteString(whereSQL)
		args = append(args, whereArgs...)
	}

	returning := q.returning
	if len(returning) == 0 {
		res, err := q.db.ExecContext(ctx, query.String(), args...)
		if err != nil {
			return nil, 0, err
		}
		rowsAffected, _ := res.RowsAffected()
		return nil, rowsAffected, nil
	}

	query.WriteString(" RETURNING ")
	colMappers := make([]func(*Post, []any, int), len(returning))

	for i, col := range returning {
		if i > 0 {
			query.WriteString(", ")
		}
		query.WriteString(col.String())

		colName := col.String()
		asIdx := strings.Index(strings.ToUpper(colName), " AS ")
		if asIdx >= 0 {
			colName = colName[:asIdx]
		}
		idx := strings.LastIndexByte(colName, '.')
		if idx >= 0 {
			colName = colName[idx+1:]
		}
		colName = strings.Trim(colName, `"`)

		switch colName {
		case "id":
			colMappers[i] = func(row *Post, ptrs []any, idx int) {
				ptrs[idx] = &row.ID
			}
		case "author_id":
			colMappers[i] = func(row *Post, ptrs []any, idx int) {
				ptrs[idx] = &row.AuthorID
			}
		case "title":
			colMappers[i] = func(row *Post, ptrs []any, idx int) {
				ptrs[idx] = &row.Title
			}
		case "body":
			colMappers[i] = func(row *Post, ptrs []any, idx int) {
				ptrs[idx] = &row.Body
			}
		case "views":
			colMappers[i] = func(row *Post, ptrs []any, idx int) {
				ptrs[idx] = &row.Views
			}
		default:
			return nil, 0, fmt.Errorf("unknown returning column -> %s", col.String())
		}
	}

	dbRows, err := q.db.QueryContext(ctx, query.String(), args...)
	if err != nil {
		return nil, 0, err
	}
	defer func(dbRows *sql.Rows) {
		_ = dbRows.Close()
	}(dbRows)

	var results = make([]*Post, 0)
	ptrs := make([]any, len(colMappers))
	for dbRows.Next() {
		var clone Post
		for j, mapper := range colMappers {
			mapper(&clone, ptrs, j)
		}

		err = dbRows.Scan(ptrs...)
		if err != nil {
			return nil, 0, err
		}
		results = append(results, &clone)
	}

	err = dbRows.Err()
	if err != nil {
		return nil, 0, err
	}

	return results, int64(len(results)), nil
}

// Upsert executes a MERGE INTO statement for a single
// Post record.
func (q *PostQuery) Upsert(
	ctx context.Context,
	conflictCols []rootpkg.Column,
	opts ...PostCreateOption,
) (*Post, error) {
	res, err := q.UpsertMany(ctx, conflictCols, opts)
	if err != nil {
		return nil, err
	}
	if len(res) == 0 {
		return nil, nil
	}
	return res[0], nil
}

// UpsertMany executes a MERGE INTO statement for multiple
// Post records in a single batch operation.
func (q *PostQuery) UpsertMany(
	ctx context.Context,
	conflictCols []rootpkg.Column,
	items ...[]PostCreateOption,
) ([]*Post, error) {
	if len(items) == 0 {
		return nil, nil
	}
	if len(conflictCols) == 0 {
		return nil, errors.New("upsert requires at least one conflict column")
	}

	// Evaluate the functional options into maps of column -> value
	rowsData := make([]map[rootpkg.Column]any, 0, len(items))
	var activeCols []rootpkg.Column
	colSet := make(map[rootpkg.Column]struct{})

	for _, rowOpts := range items {
		m := make(map[rootpkg.Column]any)
		for _, opt := range rowOpts {
			opt(m)
		}
		rowsData = append(rowsData, m)

		// Track all unique columns touched across the entire batch
		for col := range m {
			_, exists := colSet[col]
			if !exists {
				colSet[col] = struct{}{}
				activeCols = append(activeCols, col)
			}
		}
	}

	if len(activeCols) == 0 {
		return nil, errors.New("no columns to upsert")
	}

	var query strings.Builder
	query.Grow(1024)
	query.WriteString(
		`MERGE INTO "public"."posts" AS t USING (SELECT * FROM UNNEST(`,
	)

	var args = make([]any, len(activeCols))
	for i, col := range activeCols {
		if i > 0 {
			query.WriteString(", ")
		}
		query.WriteString("$")
		query.WriteString(strconv.Itoa(i + 1))

		// Prepare the columnar array for unnest
		colVals := make([]any, len(items))
		for j, m := range rowsData {
			colVals[j] = m[col]
		}
		args[i] = colVals
	}

	query.WriteString(") WITH ORDINALITY AS val(")
	for i, col := range activeCols {
		if i > 0 {
			query.WriteString(", ")
		}
		query.WriteString(col.String())
	}
	query.WriteString(", ord)) AS s ON ")

	for i, col := range conflictCols {
		if i > 0 {
			query.WriteString(" AND ")
		}
		colName := col.String()
		asIdx := strings.Index(strings.ToUpper(colName), " AS ")
		if asIdx >= 0 {
			colName = colName[:asIdx]
		}
		idx := strings.LastIndexByte(colName, '.')
		if idx >= 0 {
			colName = colName[idx+1:]
		}
		colName = strings.Trim(colName, `"`)
		query.WriteString("t.")
		query.WriteString(colName)
		query.WriteString(" = s.")
		query.WriteString(col.String())
	}

	query.WriteString(" WHEN MATCHED THEN UPDATE SET ")
	for i, col := range activeCols {
		if i > 0 {
			query.WriteString(", ")
		}
		colName := col.String()
		asIdx := strings.Index(strings.ToUpper(colName), " AS ")
		if asIdx >= 0 {
			colName = colName[:asIdx]
		}
		idx := strings.LastIndexByte(colName, '.')
		if idx >= 0 {
			colName = colName[idx+1:]
		}
		colName = strings.Trim(colName, `"`)
		query.WriteString(colName)
		query.WriteString(" = s.")
		query.WriteString(colName)
	}

	query.WriteString(" WHEN NOT MATCHED THEN INSERT (")
	for i, col := range activeCols {
		if i > 0 {
			query.WriteString(", ")
		}
		colName := col.String()
		asIdx := strings.Index(strings.ToUpper(colName), " AS ")
		if asIdx >= 0 {
			colName = colName[:asIdx]
		}
		idx := strings.LastIndexByte(colName, '.')
		if idx >= 0 {
			colName = colName[idx+1:]
		}
		colName = strings.Trim(colName, `"`)
		query.WriteString(colName)
	}
	query.WriteString(") VALUES (")
	for i, col := range activeCols {
		if i > 0 {
			query.WriteString(", ")
		}
		colName := col.String()
		asIdx := strings.Index(strings.ToUpper(colName), " AS ")
		if asIdx >= 0 {
			colName = colName[:asIdx]
		}
		idx := strings.LastIndexByte(colName, '.')
		if idx >= 0 {
			colName = colName[idx+1:]
		}
		colName = strings.Trim(colName, `"`)
		query.WriteString("s.")
		query.WriteString(colName)
	}
	query.WriteString(")")

	returning := q.returning
	if len(returning) == 0 {
		_, err := q.db.ExecContext(ctx, query.String(), args...)
		if err != nil {
			return nil, err
		}
		return nil, nil
	}

	query.WriteString(" RETURNING ")
	colMappers := make([]func(*Post, []any, int), len(returning))

	for i, col := range returning {
		if i > 0 {
			query.WriteString(", ")
		}
		colName := col.String()
		asIdx := strings.Index(strings.ToUpper(colName), " AS ")
		if asIdx >= 0 {
			colName = colName[:asIdx]
		}
		idx := strings.LastIndexByte(colName, '.')
		if idx >= 0 {
			colName = colName[idx+1:]
		}
		colName = strings.Trim(colName, `"`)
		query.WriteString("t.")
		query.WriteString(colName)

		switch colName {
		case "id":
			colMappers[i] = func(row *Post, ptrs []any, idx int) {
				ptrs[idx] = &row.ID
			}
		case "author_id":
			colMappers[i] = func(row *Post, ptrs []any, idx int) {
				ptrs[idx] = &row.AuthorID
			}
		case "title":
			colMappers[i] = func(row *Post, ptrs []any, idx int) {
				ptrs[idx] = &row.Title
			}
		case "body":
			colMappers[i] = func(row *Post, ptrs []any, idx int) {
				ptrs[idx] = &row.Body
			}
		case "views":
			colMappers[i] = func(row *Post, ptrs []any, idx int) {
				ptrs[idx] = &row.Views
			}
		default:
			return nil, fmt.Errorf("unknown returning column -> %s", col.String())
		}
	}

	query.WriteString(", s.ord::INT")

	dbRows, err := q.db.QueryContext(ctx, query.String(), args...)
	if err != nil {
		return nil, err
	}
	defer func(dbRows *sql.Rows) {
		_ = dbRows.Close()
	}(dbRows)

	var results = make([]*Post, len(items))

	ptrs := make([]any, len(colMappers)+1)
	var ord int
	ptrs[len(colMappers)] = &ord

	for dbRows.Next() {
		var clone Post
		for j, mapper := range colMappers {
			mapper(&clone, ptrs, j)
		}

		err = dbRows.Scan(ptrs...)
		if err != nil {
			return nil, err
		}

		// Ordinality is 1-based, ensuring correct positional mapping
		if ord > 0 && ord <= len(results) {
			results[ord-1] = &clone
		}
	}

	err = dbRows.Err()
	if err != nil {
		return nil, err
	}

	// Filter out any missed rows (e.g., if a WHERE constraint on the MERGE
	// prevented matching/inserting)
	var compacted = make([]*Post, 0, len(items))
	for _, r := range results {
		if r != nil {
			compacted = append(compacted, r)
		}
	}

	return compacted, nil
}

// Delete removes one or more Post records from the database based
// on the current query constraints, returning the number of rows affected.
func (q *PostQuery) Delete(
	ctx context.Context,
) (int64, error) {
	var query strings.Builder
	query.Grow(128)
	query.WriteString(`DELETE FROM "public"."posts"`)
	if q.alias != "" {
		query.WriteString(" AS ")
		query.WriteString(q.alias)
	}

	var args = make([]any, 0, 16)
	paramIdx := 1

	if len(q.wheres) > 0 {
		query.WriteString(" WHERE ")
		whereSQL, whereArgs, err := rootpkg.BuildConditions(q.wheres, &paramIdx)
		if err != nil {
			return 0, err
		}
		query.WriteString(whereSQL)
		args = append(args, whereArgs...)
	}

	res, err := q.db.ExecContext(ctx, query.String(), args...)
	if err != nil {
		if errors.Is(err, sql.ErrNoRows) {
			return 0, nil
		}
		return 0, err
	}
	return res.RowsAffected()
}

