// Paginate limits the query to a specific page and calculates the total count.
func (q *PostTagQuery) PaginateWithCount(
	ctx context.Context, page int, pageSize int,
) (*PostTagCountPagination, error) {
	if page < 1 {
		page = 1
	}
	if pageSize < 1 {
		pageSize = 10
	}
	offset := (page - 1) * pageSize

	_, colMappers, err := q.buildSelect()
	if err != nil {
		return nil, err
	}

	clone := q.Limit(pageSize).Offset(offset)
	queryStr, args, err := clone.ToSelectSQL(1, true)
	if err != nil {
		return nil, err
	}

	rows, err := clone.db.QueryContext(ctx, queryStr, args...)
	if err != nil {
		return nil, err
	}
	defer func(rows *sql.Rows) {
		_ = rows.Close()
	}(rows)

	var results []*PostTag
	var totalCount int

	ptrs := make([]any, len(colMappers)+1)
	ptrs[len(colMappers)] = &totalCount

	for rows.Next() {
		var row PostTag
		for i, mapper := range colMappers {
			mapper(&row, ptrs, i)
		}

		err = rows.Scan(ptrs...)
		if err != nil {
			return nil, err
		}
		results = append(results, &row)
	}

	err = rows.Err()
	if err != nil {
		return nil, err
	}

	if len(results) > 0 {
		err := clone.loadEdges(ctx, results)
		if err != nil {
			return nil, err
		}
	}

	return &PostTagCountPagination{
		Items:      results,
		TotalCount: totalCount,
	}, nil
}

// PaginateSimple executes the query and returns a paginated result set without a total count.
// Instead, it fetches one extra record to determine if there are more records available.
func (q *PostTagQuery) PaginateSimple(
	ctx context.Context, page int, pageSize int,
) (*PostTagSimplePagination, error) {
	if page < 1 {
		page = 1
	}
	if pageSize < 1 {
		pageSize = 10
	}

	limit := pageSize + 1
	offset := (page - 1) * pageSize

	items, err := q.Limit(limit).Offset(offset).Get(ctx)
	if err != nil {
		return nil, err
	}

	hasMore := false
	if len(items) > pageSize {
		hasMore = true
		items = items[:pageSize]
	}

	return &PostTagSimplePagination{
		Items:   items,
		HasMore: hasMore,
	}, nil
}

// loadEdges eager-loads the requested relationships for a given set of
// PostTag records.
func (q *PostTagQuery) loadEdges(
	ctx context.Context, results []*PostTag,
) error {
	if len(results) == 0 {
		return nil
	}

	if q.withPostTagsPost != nil {
		var keys [][]any
		keyMap := make(map[string]struct{})

		for _, item := range results {
			tuple := make([]any, 1)
			skip := false
			tuple[0] = item.PostID

			if skip {
				continue
			}

			keyStr := fmt.Sprintf("%v", tuple)
			_, exists := keyMap[keyStr]
			if !exists {
				keyMap[keyStr] = struct{}{}
				keys = append(keys, tuple)
			}
		}

		if len(keys) > 0 {
			var sqlBuilder strings.Builder
			var args []any
			sqlBuilder.WriteString("id = ANY(?)")
			typedArgs := make([]int64, 0, len(keys))
			for _, k := range keys {
				typedArgs = append(typedArgs, k[0].(int64))
			}
			args = []any{typedArgs}

			builder := q.withPostTagsPost.Where(rootpkg.WhereCondition{
				Sql:  sqlBuilder.String(),
				Args: args,
			})
			loaded, err := builder.Get(ctx)
			if err != nil {
				return err
			}
			m := make(map[string]*Post)
			for _, rel := range loaded {
				tuple := make([]any, 1)
				skip := false
				tuple[0] = rel.ID
				if !skip {
					keyStr := fmt.Sprintf("%v", tuple)
					m[keyStr] = rel
				}
			}
			for _, item := range results {
				tuple := make([]any, 1)
				skip := false
				tuple[0] = item.PostID
				if !skip {
					keyStr := fmt.Sprintf("%v", tuple)
					rel, ok := m[keyStr]
					if ok {
						item.PostTagsPost = rel
					}
				}
			}
		}
	}

	if q.withMetrics != nil {
		var keys [][]any
		keyMap := make(map[string]struct{})

		for _, item := range results {
			tuple := make([]any, 2)
			skip := false
			tuple[0] = item.PostID
			tuple[1] = item.TagID

			if skip {
				continue
			}

			keyStr := fmt.Sprintf("%v", tuple)
			_, exists := keyMap[keyStr]
			if !exists {
				keyMap[keyStr] = struct{}{}
				keys = append(keys, tuple)
			}
		}

		if len(keys) > 0 {
			var sqlBuilder strings.Builder
			var args []any
			sqlBuilder.WriteString("(")
			sqlBuilder.WriteString("post_id")
			sqlBuilder.WriteString(", ")
			sqlBuilder.WriteString("tag_id")
			sqlBuilder.WriteString(") IN (")

			args = make([]any, 0, len(keys)*2)
			for i, tuple := range keys {
				if i > 0 {
					sqlBuilder.WriteString(", ")
				}
				sqlBuilder.WriteString("(")
				sqlBuilder.WriteString("?")
				sqlBuilder.WriteString(", ")
				sqlBuilder.WriteString("?")
				sqlBuilder.WriteString(")")

				args = append(args, tuple...)
			}
			sqlBuilder.WriteString(")")

			builder := q.withMetrics.Where(rootpkg.WhereCondition{
				Sql:  sqlBuilder.String(),
				Args: args,
			})
			loaded, err := builder.Get(ctx)
			if err != nil {
				return err
			}
			m := make(map[string][]*PostTagMetric)
			for _, rel := range loaded {
				tuple := make([]any, 2)
				skip := false
				tuple[0] = rel.PostID
				tuple[1] = rel.TagID
				if !skip {
					keyStr := fmt.Sprintf("%v", tuple)
					m[keyStr] = append(m[keyStr], rel)
				}
			}
			for _, item := range results {
				tuple := make([]any, 2)
				skip := false
				tuple[0] = item.PostID
				tuple[1] = item.TagID
				if !skip {
					keyStr := fmt.Sprintf("%v", tuple)
					rels, ok := m[keyStr]
					if ok {
						item.Metrics = rels
					}
				}
			}
		}
	}
	return nil
}

