// Get executes the query and returns a slice of matching
// Tag pointers.
func (q *TagQuery) Get(
	ctx context.Context,
) ([]*Tag, error) {
	_, colMappers, err := q.buildSelect()
	if err != nil {
		return nil, err
	}

	queryStr, args, err := q.ToSelectSQL(1, false)
	if err != nil {
		return nil, err
	}

	rows, err := q.db.QueryContext(ctx, queryStr, args...)
	if err != nil {
		return nil, err
	}
	defer func(rows *sql.Rows) {
		_ = rows.Close()
	}(rows)

	var results []*Tag
	ptrs := make([]any, len(colMappers))
	for rows.Next() {
		var row Tag
		for i, mapper := range colMappers {
			mapper(&row, ptrs, i)
		}

		err = rows.Scan(ptrs...)
		if err != nil {
			return nil, err
		}
		results = append(results, &row)
	}

	err = rows.Err()
	if err != nil {
		return nil, err
	}

	if len(results) > 0 {
		err := q.loadEdges(ctx, results)
		if err != nil {
			return nil, err
		}
	}

	return results, nil
}

// First executes the query, wrapping it with a LIMIT 1. It returns the first
// matching Tag pointer, or nil if no records are found.
func (q *TagQuery) First(
	ctx context.Context,
) (*Tag, error) {
	clone := q.Limit(1)

	_, colMappers, err := clone.buildSelect()
	if err != nil {
		return nil, err
	}

	queryStr, args, err := clone.ToSelectSQL(1, false)
	if err != nil {
		return nil, err
	}

	var row Tag
	ptrs := make([]any, len(colMappers))
	for i, mapper := range colMappers {
		mapper(&row, ptrs, i)
	}

	err = clone.db.QueryRowContext(ctx, queryStr, args...).Scan(ptrs...)
	if err != nil {
		if errors.Is(err, sql.ErrNoRows) {
			return nil, nil
		}
		return nil, err
	}

	err = clone.loadEdges(ctx, []*Tag{&row})
	if err != nil {
		return nil, err
	}

	return &row, nil
}

// Exists builds and executes an optimized SELECT EXISTS(...) query.
func (q *TagQuery) Exists(ctx context.Context) (bool, error) {
	var query strings.Builder
	query.Grow(256)
	query.WriteString("SELECT EXISTS(")
	query.WriteString(`SELECT 1 FROM "public"."tags"`)
	if q.alias != "" {
		query.WriteString(" AS ")
		query.WriteString(q.alias)
	}

	var args []any
	paramIdx := 1

	if len(q.wheres) > 0 {
		query.WriteString(" WHERE ")
		whereSQL, whereArgs, err := rootpkg.BuildConditions(q.wheres, &paramIdx)
		if err != nil {
			return false, err
		}
		query.WriteString(whereSQL)
		args = append(args, whereArgs...)
	}

	if len(q.groupBys) > 0 {
		query.WriteString(" GROUP BY ")
		for i, ob := range q.groupBys {
			if i > 0 {
				query.WriteString(", ")
			}
			query.WriteString(ob.String())
		}
	}

	if len(q.havings) > 0 {
		query.WriteString(" HAVING ")
		havingSQL, havingArgs, err := rootpkg.BuildConditions(q.havings, &paramIdx)
		if err != nil {
			return false, err
		}
		query.WriteString(havingSQL)
		args = append(args, havingArgs...)
	}

	query.WriteString(")")

	var exists bool
	err := q.db.QueryRowContext(ctx, query.String(), args...).Scan(&exists)
	if err != nil {
		return false, err
	}
	return exists, nil
}

// Paginate limits the query to a specific page and calculates the total count.
func (q *TagQuery) PaginateWithCount(
	ctx context.Context, page int, pageSize int,
) (*TagCountPagination, error) {
	if page < 1 {
		page = 1
	}
	if pageSize < 1 {
		pageSize = 10
	}
	offset := (page - 1) * pageSize

	_, colMappers, err := q.buildSelect()
	if err != nil {
		return nil, err
	}

	clone := q.Limit(pageSize).Offset(offset)
	queryStr, args, err := clone.ToSelectSQL(1, true)
	if err != nil {
		return nil, err
	}

	rows, err := clone.db.QueryContext(ctx, queryStr, args...)
	if err != nil {
		return nil, err
	}
	defer func(rows *sql.Rows) {
		_ = rows.Close()
	}(rows)

	var results []*Tag
	var totalCount int

	ptrs := make([]any, len(colMappers)+1)
	ptrs[len(colMappers)] = &totalCount

	for rows.Next() {
		var row Tag
		for i, mapper := range colMappers {
			mapper(&row, ptrs, i)
		}

		err = rows.Scan(ptrs...)
		if err != nil {
			return nil, err
		}
		results = append(results, &row)
	}

	err = rows.Err()
	if err != nil {
		return nil, err
	}

	if len(results) > 0 {
		err := clone.loadEdges(ctx, results)
		if err != nil {
			return nil, err
		}
	}

	return &TagCountPagination{
		Items:      results,
		TotalCount: totalCount,
	}, nil
}

// PaginateSimple executes the query and returns a paginated result set without a total count.
// Instead, it fetches one extra record to determine if there are more records available.
func (q *TagQuery) PaginateSimple(
	ctx context.Context, page int, pageSize int,
) (*TagSimplePagination, error) {
	if page < 1 {
		page = 1
	}
	if pageSize < 1 {
		pageSize = 10
	}

	limit := pageSize + 1
	offset := (page - 1) * pageSize

	items, err := q.Limit(limit).Offset(offset).Get(ctx)
	if err != nil {
		return nil, err
	}

	hasMore := false
	if len(items) > pageSize {
		hasMore = true
		items = items[:pageSize]
	}

	return &TagSimplePagination{
		Items:   items,
		HasMore: hasMore,
	}, nil
}

