// CreateMany inserts multiple Tag records into the database in a
// single batch operation.
func (q *TagQuery) CreateMany(
	ctx context.Context, items ...[]TagCreateOption,
) ([]*Tag, error) {
	if len(items) == 0 {
		return nil, nil
	}

	// Evaluate the functional options into maps of column -> value
	rowsData := make([]map[rootpkg.Column]any, 0, len(items))
	var activeCols []rootpkg.Column
	colSet := make(map[rootpkg.Column]struct{})

	for _, rowOpts := range items {
		m := make(map[rootpkg.Column]any)
		for _, opt := range rowOpts {
			opt(m)
		}
		rowsData = append(rowsData, m)

		// Track all unique columns touched across the entire batch
		for col := range m {
			_, exists := colSet[col]
			if !exists {
				colSet[col] = struct{}{}
				activeCols = append(activeCols, col)
			}
		}
	}

	if len(activeCols) == 0 {
		return nil, errors.New("no columns to insert")
	}

	var query strings.Builder
	var numBuf [20]byte
	query.Grow(512)
	query.WriteString(`INSERT INTO "public"."tags" (`)

	for i, col := range activeCols {
		if i > 0 {
			query.WriteString(", ")
		}
		query.WriteString(col.String())
	}
	query.WriteString(") VALUES ")

	var args = make([]any, 0, len(items)*len(activeCols))
	paramIdx := 1

	for i, m := range rowsData {
		if i > 0 {
			query.WriteString(", ")
		}
		query.WriteString("(")

		for j, col := range activeCols {
			if j > 0 {
				query.WriteString(", ")
			}
			val, exists := m[col]
			if !exists {
				query.WriteString("DEFAULT")
			} else {
				query.WriteString("$")
				query.Write(strconv.AppendInt(numBuf[:0], int64(paramIdx), 10))
				args = append(args, val)
				paramIdx++
			}
		}
		query.WriteString(")")
	}

	returning := q.returning
	if len(returning) == 0 {
		_, err := q.db.ExecContext(ctx, query.String(), args...)
		if err != nil {
			return nil, err
		}
		return nil, nil
	}

	query.WriteString(" RETURNING ")
	colMappers := make([]func(*Tag, []any, int), len(returning))

	for i, col := range returning {
		if i > 0 {
			query.WriteString(", ")
		}
		query.WriteString(col.String())

		colName := col.String()
		asIdx := strings.Index(strings.ToUpper(colName), " AS ")
		if asIdx >= 0 {
			colName = colName[:asIdx]
		}
		idx := strings.LastIndexByte(colName, '.')
		if idx >= 0 {
			colName = colName[idx+1:]
		}
		colName = strings.Trim(colName, `"`)

		switch colName {
		case "id":
			colMappers[i] = func(row *Tag, ptrs []any, idx int) {
				ptrs[idx] = &row.ID
			}
		case "name":
			colMappers[i] = func(row *Tag, ptrs []any, idx int) {
				ptrs[idx] = &row.Name
			}
		default:
			return nil, fmt.Errorf("unknown returning column -> %s", col.String())
		}
	}

	dbRows, err := q.db.QueryContext(ctx, query.String(), args...)
	if err != nil {
		return nil, err
	}
	defer func(dbRows *sql.Rows) {
		_ = dbRows.Close()
	}(dbRows)

	var results = make([]*Tag, 0, len(items))
	ptrs := make([]any, len(colMappers))
	for i := 0; dbRows.Next(); i++ {
		if i >= len(items) {
			return nil, errors.New("database returned more rows than expected")
		}

		var clone Tag
		for j, mapper := range colMappers {
			mapper(&clone, ptrs, j)
		}

		err = dbRows.Scan(ptrs...)
		if err != nil {
			return nil, err
		}
		results = append(results, &clone)
	}

	err = dbRows.Err()
	if err != nil {
		return nil, err
	}

	return results, nil
}

