// Get executes the query and returns a slice of matching
// TemporaryLog pointers.
func (q *TemporaryLogQuery) Get(
	ctx context.Context,
) ([]*TemporaryLog, error) {
	_, colMappers, err := q.buildSelect()
	if err != nil {
		return nil, err
	}

	queryStr, args, err := q.ToSelectSQL(1, false)
	if err != nil {
		return nil, err
	}

	rows, err := q.db.QueryContext(ctx, queryStr, args...)
	if err != nil {
		return nil, err
	}
	defer func(rows *sql.Rows) {
		_ = rows.Close()
	}(rows)

	var results []*TemporaryLog
	ptrs := make([]any, len(colMappers))
	for rows.Next() {
		var row TemporaryLog
		for i, mapper := range colMappers {
			mapper(&row, ptrs, i)
		}

		err = rows.Scan(ptrs...)
		if err != nil {
			return nil, err
		}
		results = append(results, &row)
	}

	err = rows.Err()
	if err != nil {
		return nil, err
	}

	if len(results) > 0 {
		err := q.loadEdges(ctx, results)
		if err != nil {
			return nil, err
		}
	}

	return results, nil
}

// First executes the query, wrapping it with a LIMIT 1. It returns the first
// matching TemporaryLog pointer, or nil if no records are found.
func (q *TemporaryLogQuery) First(
	ctx context.Context,
) (*TemporaryLog, error) {
	clone := q.Limit(1)

	_, colMappers, err := clone.buildSelect()
	if err != nil {
		return nil, err
	}

	queryStr, args, err := clone.ToSelectSQL(1, false)
	if err != nil {
		return nil, err
	}

	var row TemporaryLog
	ptrs := make([]any, len(colMappers))
	for i, mapper := range colMappers {
		mapper(&row, ptrs, i)
	}

	err = clone.db.QueryRowContext(ctx, queryStr, args...).Scan(ptrs...)
	if err != nil {
		if errors.Is(err, sql.ErrNoRows) {
			return nil, nil
		}
		return nil, err
	}

	err = clone.loadEdges(ctx, []*TemporaryLog{&row})
	if err != nil {
		return nil, err
	}

	return &row, nil
}

