// PaginateSimple executes the query and returns a paginated result set without a total count.
// Instead, it fetches one extra record to determine if there are more records available.
func (q *TemporaryLogQuery) PaginateSimple(
	ctx context.Context, page int, pageSize int,
) (*TemporaryLogSimplePagination, error) {
	if page < 1 {
		page = 1
	}
	if pageSize < 1 {
		pageSize = 10
	}

	limit := pageSize + 1
	offset := (page - 1) * pageSize

	items, err := q.Limit(limit).Offset(offset).Get(ctx)
	if err != nil {
		return nil, err
	}

	hasMore := false
	if len(items) > pageSize {
		hasMore = true
		items = items[:pageSize]
	}

	return &TemporaryLogSimplePagination{
		Items:   items,
		HasMore: hasMore,
	}, nil
}

