// Create inserts a single User record into the database.
func (q *UserQuery) Create(
	ctx context.Context, opts ...UserCreateOption,
) (*User, error) {
	if len(q.returning) == 0 {
		q = q.Returning(
			UserColumns.ID,
			UserColumns.Username,
			UserColumns.Email,
			UserColumns.Status,
			UserColumns.BillingAddress,
			UserColumns.Age,
			UserColumns.Metadata,
			UserColumns.CreatedAt,
		)
	}
	res, err := q.CreateMany(ctx, opts)
	if err != nil {
		return nil, err
	}
	if len(res) == 0 {
		return nil, nil
	}
	return res[0], nil
}

// CreateMany inserts multiple User records into the database in a
// single batch operation.
func (q *UserQuery) CreateMany(
	ctx context.Context, items ...[]UserCreateOption,
) ([]*User, error) {
	if len(items) == 0 {
		return nil, nil
	}

	// Evaluate the functional options into maps of column -> value
	rowsData := make([]map[rootpkg.Column]any, 0, len(items))
	var activeCols []rootpkg.Column
	colSet := make(map[rootpkg.Column]struct{})

	for _, rowOpts := range items {
		m := make(map[rootpkg.Column]any)
		for _, opt := range rowOpts {
			opt(m)
		}
		rowsData = append(rowsData, m)

		// Track all unique columns touched across the entire batch
		for col := range m {
			_, exists := colSet[col]
			if !exists {
				colSet[col] = struct{}{}
				activeCols = append(activeCols, col)
			}
		}
	}

	if len(activeCols) == 0 {
		return nil, errors.New("no columns to insert")
	}

	var query strings.Builder
	var numBuf [20]byte
	query.Grow(512)
	query.WriteString(`INSERT INTO "public"."users" (`)

	for i, col := range activeCols {
		if i > 0 {
			query.WriteString(", ")
		}
		query.WriteString(col.String())
	}
	query.WriteString(") VALUES ")

	var args = make([]any, 0, len(items)*len(activeCols))
	paramIdx := 1

	for i, m := range rowsData {
		if i > 0 {
			query.WriteString(", ")
		}
		query.WriteString("(")

		for j, col := range activeCols {
			if j > 0 {
				query.WriteString(", ")
			}
			val, exists := m[col]
			if !exists {
				query.WriteString("DEFAULT")
			} else {
				query.WriteString("$")
				query.Write(strconv.AppendInt(numBuf[:0], int64(paramIdx), 10))
				args = append(args, val)
				paramIdx++
			}
		}
		query.WriteString(")")
	}

	returning := q.returning
	if len(returning) == 0 {
		_, err := q.db.ExecContext(ctx, query.String(), args...)
		if err != nil {
			return nil, err
		}
		return nil, nil
	}

	query.WriteString(" RETURNING ")
	colMappers := make([]func(*User, []any, int), len(returning))

	for i, col := range returning {
		if i > 0 {
			query.WriteString(", ")
		}
		query.WriteString(col.String())

		colName := col.String()
		asIdx := strings.Index(strings.ToUpper(colName), " AS ")
		if asIdx >= 0 {
			colName = colName[:asIdx]
		}
		idx := strings.LastIndexByte(colName, '.')
		if idx >= 0 {
			colName = colName[idx+1:]
		}
		colName = strings.Trim(colName, `"`)

		switch colName {
		case "id":
			colMappers[i] = func(row *User, ptrs []any, idx int) {
				ptrs[idx] = &row.ID
			}
		case "username":
			colMappers[i] = func(row *User, ptrs []any, idx int) {
				ptrs[idx] = &row.Username
			}
		case "email":
			colMappers[i] = func(row *User, ptrs []any, idx int) {
				ptrs[idx] = &row.Email
			}
		case "status":
			colMappers[i] = func(row *User, ptrs []any, idx int) {
				ptrs[idx] = &row.Status
			}
		case "billing_address":
			colMappers[i] = func(row *User, ptrs []any, idx int) {
				ptrs[idx] = &row.BillingAddress
			}
		case "age":
			colMappers[i] = func(row *User, ptrs []any, idx int) {
				ptrs[idx] = &row.Age
			}
		case "metadata":
			colMappers[i] = func(row *User, ptrs []any, idx int) {
				ptrs[idx] = &row.Metadata
			}
		case "created_at":
			colMappers[i] = func(row *User, ptrs []any, idx int) {
				ptrs[idx] = &row.CreatedAt
			}
		default:
			return nil, fmt.Errorf("unknown returning column -> %s", col.String())
		}
	}

	dbRows, err := q.db.QueryContext(ctx, query.String(), args...)
	if err != nil {
		return nil, err
	}
	defer func(dbRows *sql.Rows) {
		_ = dbRows.Close()
	}(dbRows)

	var results = make([]*User, 0, len(items))
	ptrs := make([]any, len(colMappers))
	for i := 0; dbRows.Next(); i++ {
		if i >= len(items) {
			return nil, errors.New("database returned more rows than expected")
		}

		var clone User
		for j, mapper := range colMappers {
			mapper(&clone, ptrs, j)
		}

		err = dbRows.Scan(ptrs...)
		if err != nil {
			return nil, err
		}
		results = append(results, &clone)
	}

	err = dbRows.Err()
	if err != nil {
		return nil, err
	}

	return results, nil
}

